const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Array<Item> };

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<QuoteStep>;
};

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const itemPremiumWithFirstInsuranceSurcharge = (item: Item): number =>
  BASE_PREMIUM[item.type] * (1 + FIRST_INSURANCE_SURCHARGE_RATE);

const quotePremium = (step: QuoteStep): number => {
  const itemsTotal = step.items.reduce(
    (sum, item) => sum + itemPremiumWithFirstInsuranceSurcharge(item),
    0,
  );
  return Math.ceil(itemsTotal) + PROCESSING_FEE;
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
  return { results };
};

